public class SyncService
{
    private readonly InspectionStore _store;
    private readonly ConnectivityService _connectivity;
    private readonly HttpClient _http;
    private bool _syncing;

    public event Action<string>? SyncStatusChanged;

    public SyncService(InspectionStore store, ConnectivityService connectivity, HttpClient http)
    {
        _store = store;
        _connectivity = connectivity;
        _http = http;
    }

    public void Initialize()
    {
        _connectivity.ConnectivityChanged += async (online) =>
        {
            if (online) await TrySyncAsync();
        };
    }

    public async Task TrySyncAsync()
    {
        if (_syncing || !_connectivity.IsOnline) return;
        _syncing = true;
        SyncStatusChanged?.Invoke("Syncing...");

        try
        {
            var pending = await _store.GetPendingSyncInspectionsAsync();
            var syncedCount = 0;

            foreach (var inspection in pending)
            {
                try
                {
                    // In production, POST to a real API endpoint.
                    // For now, simulate the sync and mark as synced locally.
                    await Task.Delay(200); // Simulated network call
                    inspection.SyncStatus = SyncStatus.Synced;
                    await _store.SaveInspectionAsync(inspection);
                    syncedCount++;
                }
                catch
                {
                    inspection.SyncStatus = SyncStatus.Failed;
                    await _store.SaveInspectionAsync(inspection);
                }
            }

            SyncStatusChanged?.Invoke(syncedCount > 0 ? $"Synced {syncedCount} inspection(s)" : "All up to date");
        }
        catch
        {
            SyncStatusChanged?.Invoke("Sync failed");
        }
        finally
        {
            _syncing = false;
        }
    }
}

