// IndexedDB wrapper for offline storage
const DB_NAME = 'SiteInspectorDB';
const DB_VERSION = 1;

let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const database = e.target.result;
            if (!database.objectStoreNames.contains('sites')) {
                database.createObjectStore('sites', { keyPath: 'id' });
            }
            if (!database.objectStoreNames.contains('inspections')) {
                const store = database.createObjectStore('inspections', { keyPath: 'id' });
                store.createIndex('siteId', 'siteId', { unique: false });
                store.createIndex('syncStatus', 'syncStatus', { unique: false });
            }
        };
        request.onsuccess = (e) => { db = e.target.result; resolve(db); };
        request.onerror = (e) => reject(e.target.error);
    });
}

function doTransaction(storeName, mode, operation) {
    return openDb().then(database => {
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, mode);
            const store = tx.objectStore(storeName);
            const request = operation(store);
            if (request) {
                request.onsuccess = () => resolve(request.result);
                request.onerror = () => reject(request.error);
            } else {
                tx.oncomplete = () => resolve();
                tx.onerror = () => reject(tx.error);
            }
        });
    });
}

window.siteInspectorDb = {
    putItem: (storeName, item) =>
        doTransaction(storeName, 'readwrite', store => store.put(JSON.parse(item))),

    getItem: (storeName, id) =>
        doTransaction(storeName, 'readonly', store => store.get(id))
            .then(r => r ? JSON.stringify(r) : null),

    getAllItems: (storeName) =>
        doTransaction(storeName, 'readonly', store => store.getAll())
            .then(r => JSON.stringify(r || [])),

    getByIndex: (storeName, indexName, value) =>
        openDb().then(database => {
            return new Promise((resolve, reject) => {
                const tx = database.transaction(storeName, 'readonly');
                const store = tx.objectStore(storeName);
                const index = store.index(indexName);
                const request = index.getAll(value);
                request.onsuccess = () => resolve(JSON.stringify(request.result || []));
                request.onerror = () => reject(request.error);
            });
        }),

    deleteItem: (storeName, id) =>
        doTransaction(storeName, 'readwrite', store => store.delete(id)),

    clearStore: (storeName) =>
        doTransaction(storeName, 'readwrite', store => store.clear())
};

// Connectivity detection
window.connectivityHelper = {
    isOnline: () => navigator.onLine,

    registerOnlineHandler: (dotNetRef) => {
        const handler = () => dotNetRef.invokeMethodAsync('OnConnectivityChanged', navigator.onLine);
        window.addEventListener('online', handler);
        window.addEventListener('offline', handler);
        window._connectivityHandler = handler;
    },

    unregisterOnlineHandler: () => {
        if (window._connectivityHandler) {
            window.removeEventListener('online', window._connectivityHandler);
            window.removeEventListener('offline', window._connectivityHandler);
            window._connectivityHandler = null;
        }
    }
};

// Photo helper
window.photoHelper = {
    resizeImage: (dataUrl, maxWidth, maxHeight, quality) => {
        return new Promise((resolve) => {
            const img = new Image();
            img.onload = () => {
                let w = img.width, h = img.height;
                if (w > maxWidth || h > maxHeight) {
                    const ratio = Math.min(maxWidth / w, maxHeight / h);
                    w = Math.round(w * ratio);
                    h = Math.round(h * ratio);
                }
                const canvas = document.createElement('canvas');
                canvas.width = w;
                canvas.height = h;
                canvas.getContext('2d').drawImage(img, 0, 0, w, h);
                resolve(canvas.toDataURL('image/jpeg', quality));
            };
            img.src = dataUrl;
        });
    }
};

using System.Text.Json;
