        return json is null ? null : JsonSerializer.Deserialize<Site>(json, JsonOptions);
    }

    public async Task DeleteSiteAsync(string id) =>
        await _js.InvokeVoidAsync("siteInspectorDb.deleteItem", "sites", id);

    // Inspections
    public async Task SaveInspectionAsync(Inspection inspection) =>
        await _js.InvokeVoidAsync("siteInspectorDb.putItem", "inspections",
            JsonSerializer.Serialize(inspection, JsonOptions));

    public async Task<List<Inspection>> GetAllInspectionsAsync()
    {
        var json = await _js.InvokeAsync<string>("siteInspectorDb.getAllItems", "inspections");
        return JsonSerializer.Deserialize<List<Inspection>>(json, JsonOptions) ?? [];
    }

    public async Task<Inspection?> GetInspectionAsync(string id)
    {
        var json = await _js.InvokeAsync<string?>("siteInspectorDb.getItem", "inspections", id);
        return json is null ? null : JsonSerializer.Deserialize<Inspection>(json, JsonOptions);
    }

    public async Task<List<Inspection>> GetInspectionsForSiteAsync(string siteId)
    {
        var json = await _js.InvokeAsync<string>("siteInspectorDb.getByIndex", "inspections", "siteId", siteId);
        return JsonSerializer.Deserialize<List<Inspection>>(json, JsonOptions) ?? [];
    }

    public async Task<List<Inspection>> GetPendingSyncInspectionsAsync()
    {
        var json = await _js.InvokeAsync<string>("siteInspectorDb.getByIndex", "inspections", "syncStatus", "Pending");
