    private void OnSyncStatusChanged(string message)
    {
        _syncMessage = message;
        InvokeAsync(StateHasChanged);
        // Clear message after a few seconds
        _ = Task.Delay(4000).ContinueWith(_ =>
        {
            _syncMessage = "";
            InvokeAsync(StateHasChanged);
        });
    }

    public void Dispose()
    {
        Connectivity.ConnectivityChanged -= OnConnectivityChanged;
        Sync.SyncStatusChanged -= OnSyncStatusChanged;
    }
}

@page "/"
@inject InspectionStore Store
@inject NavigationManager Nav

<PageTitle>Sites — Site Inspector</PageTitle>

<div class="page-header">
    <h1>Construction Sites</h1>
    <button class="btn btn-primary" @onclick="ShowAddSite">+ Add Site</button>
</div>

@if (_showAddForm)
{
    <div class="card add-form">
        <div class="form-group">
            <label>Site Name</label>
            <input @bind="_newSiteName" @bind:event="oninput" placeholder="e.g. 123 Main St Tower" class="form-input" />
        </div>
        <div class="form-group">
            <label>Address</label>
            <input @bind="_newSiteAddress" @bind:event="oninput" placeholder="Full address" class="form-input" />
        </div>
        <div class="form-actions">
            <button class="btn btn-primary" @onclick="AddSite" disabled="@string.IsNullOrWhiteSpace(_newSiteName)">Save</button>
            <button class="btn btn-secondary" @onclick="() => _showAddForm = false">Cancel</button>
        </div>
    </div>
}

@if (_sites is null)
{
    <p class="loading">Loading sites...</p>
}
else if (_sites.Count == 0)
{
    <div class="empty-state">
        <p>📋 No construction sites yet.</p>
        <p>Tap <strong>+ Add Site</strong> to get started.</p>
    </div>
}
else
{
    <div class="card-list">
        @foreach (var site in _sites.OrderByDescending(s => s.CreatedAt))
        {
            <div class="card site-card" @onclick="() => Nav.NavigateTo($"/site/{site.Id}")">
                <div class="card-body">
                    <h2>@site.Name</h2>
                    <p class="text-muted">@site.Address</p>
                    <p class="text-small">@_inspectionCounts.GetValueOrDefault(site.Id, 0) inspection(s)</p>
                </div>
                <div class="card-chevron">›</div>
            </div>
        }
    </div>
}

@code {
    private List<Site>? _sites;
    private Dictionary<string, int> _inspectionCounts = new();
    private bool _showAddForm;
    private string _newSiteName = "";
    private string _newSiteAddress = "";

    protected override async Task OnInitializedAsync()
    {
        _sites = await Store.GetAllSitesAsync();
        var inspections = await Store.GetAllInspectionsAsync();
        _inspectionCounts = inspections.GroupBy(i => i.SiteId).ToDictionary(g => g.Key, g => g.Count());
    }

    private void ShowAddSite()
    {
        _newSiteName = "";
        _newSiteAddress = "";
        _showAddForm = true;
    }

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(_newSiteName)) return;
        var site = new Site { Name = _newSiteName.Trim(), Address = _newSiteAddress.Trim() };
        await Store.SaveSiteAsync(site);
        _sites ??= [];
        _sites.Add(site);
        _showAddForm = false;
    }
}

@page "/site/{SiteId}"
@inject InspectionStore Store
@inject NavigationManager Nav

<PageTitle>Site Details — Site Inspector</PageTitle>

<div class="page-header">
    <button class="btn btn-back" @onclick='() => Nav.NavigateTo("/")'>← Back</button>
    <h1>@(_site?.Name ?? "Loading...")</h1>
</div>

@if (_site is not null)
{
    <p class="text-muted">@_site.Address</p>

    <div class="action-bar">
        <button class="btn btn-primary btn-lg" @onclick="StartNewInspection">
            📋 New Inspection
        </button>
    </div>

    <h2 class="section-title">Inspection History</h2>

    @if (_inspections.Count == 0)
    {
        <div class="empty-state">
            <p>No inspections yet for this site.</p>
        </div>
    }
    else
    {
        <div class="card-list">
            @foreach (var insp in _inspections.OrderByDescending(i => i.CreatedAt))
            {
                <div class="card inspection-card" @onclick="() => Nav.NavigateTo($"/inspection/{insp.Id}")">
                    <div class="card-body">
                        <div class="inspection-card-top">
                            <span class="badge @(insp.Status == InspectionStatus.Completed ? "badge-success" : "badge-warning")">
                                @(insp.Status == InspectionStatus.Completed ? "Completed" : "In Progress")
                            </span>
                            <span class="badge @GetSyncBadgeClass(insp.SyncStatus)">
                                @insp.SyncStatus
                            </span>
                        </div>
                        <p class="text-small">@insp.CreatedAt.ToLocalTime().ToString("MMM d, yyyy h:mm tt")</p>
                        <p class="text-small">@insp.InspectorName</p>
                        @{
                            var total = insp.ChecklistItems.Count;
                            var checked_ = insp.ChecklistItems.Count(c => c.Result != CheckResult.NotChecked);
                            var failed = insp.ChecklistItems.Count(c => c.Result == CheckResult.Fail);
                        }
                        <p class="text-small">
                            ✅ @checked_/@total checked
                            @if (failed > 0) { <span class="text-danger"> · ❌ @failed failed</span> }
                        </p>
                    </div>
                    <div class="card-chevron">›</div>
                </div>
            }
        </div>
    }
}

@code {
    [Parameter] public string SiteId { get; set; } = "";
    private Site? _site;
    private List<Inspection> _inspections = [];

    protected override async Task OnInitializedAsync()
    {
        _site = await Store.GetSiteAsync(SiteId);
        _inspections = await Store.GetInspectionsForSiteAsync(SiteId);
    }

    private async Task StartNewInspection()
    {
        var inspection = new Inspection
        {
            SiteId = SiteId,
            SiteName = _site?.Name ?? "",
            ChecklistItems = ChecklistTemplate.CreateDefault()
        };
        await Store.SaveInspectionAsync(inspection);
        Nav.NavigateTo($"/inspection/{inspection.Id}");
    }

    private string GetSyncBadgeClass(SyncStatus status) => status switch
    {
        SyncStatus.Synced => "badge-success",
        SyncStatus.Failed => "badge-danger",
        _ => "badge-muted"
    };
}

