@page "/inspection/{InspectionId}"
@inject InspectionStore Store
@inject NavigationManager Nav
@inject IJSRuntime JS

<PageTitle>Inspection — Site Inspector</PageTitle>

<div class="page-header">
    <button class="btn btn-back" @onclick="GoBack">← Back</button>
    <h1>Inspection</h1>
</div>

@if (_inspection is null)
{
    <p class="loading">Loading...</p>
}
else
{
    <div class="inspection-tabs">
        <button class="tab @(_activeTab == "checklist" ? "active" : "")" @onclick='() => _activeTab = "checklist"'>
            📋 Checklist
        </button>
        <button class="tab @(_activeTab == "photos" ? "active" : "")" @onclick='() => _activeTab = "photos"'>
            📷 Photos (@_inspection.Photos.Count)
        </button>
        <button class="tab @(_activeTab == "notes" ? "active" : "")" @onclick='() => _activeTab = "notes"'>
            📝 Notes
        </button>
    </div>

    @if (_activeTab == "checklist")
    {
        <div class="form-group">
            <label>Inspector Name</label>
            <input class="form-input" @bind="_inspection.InspectorName" @bind:after="SaveAsync" placeholder="Your name" />
        </div>

        @foreach (var group in _inspection.ChecklistItems.GroupBy(c => c.Category))
        {
            <div class="checklist-category">
                <h3 class="category-title">@group.Key</h3>
                @foreach (var item in group)
                {
                    <div class="checklist-item @GetItemClass(item)">
                        <div class="checklist-item-text" @onclick="() => ToggleItemNotes(item.Id)">
                            <span>@item.Description</span>
                        </div>
                        <div class="checklist-buttons">
                            <button class="check-btn pass @(item.Result == CheckResult.Pass ? "active" : "")"
                                    @onclick="() => SetResult(item, CheckResult.Pass)" title="Pass">✓</button>
                            <button class="check-btn fail @(item.Result == CheckResult.Fail ? "active" : "")"
                                    @onclick="() => SetResult(item, CheckResult.Fail)" title="Fail">✗</button>
                            <button class="check-btn na @(item.Result == CheckResult.NotApplicable ? "active" : "")"
                                    @onclick="() => SetResult(item, CheckResult.NotApplicable)" title="N/A">—</button>
                        </div>
                        @if (_expandedItemId == item.Id)
                        {
                            <div class="checklist-item-notes">
                                <textarea class="form-input" placeholder="Add notes for this item..."
                                          @bind="item.Notes" @bind:after="SaveAsync" rows="2"></textarea>
                            </div>
                        }
                    </div>
                }
            </div>
        }

        <div class="inspection-summary">
            @{
                var total = _inspection.ChecklistItems.Count;
                var done = _inspection.ChecklistItems.Count(c => c.Result != CheckResult.NotChecked);
                var pass = _inspection.ChecklistItems.Count(c => c.Result == CheckResult.Pass);
                var fail = _inspection.ChecklistItems.Count(c => c.Result == CheckResult.Fail);
                var na = _inspection.ChecklistItems.Count(c => c.Result == CheckResult.NotApplicable);
            }
            <div class="summary-bar">
                <span>✅ @pass Pass</span>
                <span>❌ @fail Fail</span>
                <span>➖ @na N/A</span>
                <span>⬜ @(total - done) Remaining</span>
            </div>
            <div class="progress-bar">
                <div class="progress-fill" style="width: @(total > 0 ? (done * 100 / total) : 0)%"></div>
            </div>
        </div>
    }
    else if (_activeTab == "photos")
    {
        <div class="photo-section">
            <label class="btn btn-primary photo-upload-btn">
                📸 Take / Upload Photo
                <InputFile OnChange="OnPhotoSelected" accept="image/*" capture="environment" style="display:none" />
            </label>

            @if (_inspection.Photos.Count == 0)
            {
                <div class="empty-state">
                    <p>No photos attached yet.</p>
                </div>
            }
            else
            {
                <div class="photo-grid">
                    @foreach (var photo in _inspection.Photos.OrderByDescending(p => p.TakenAt))
                    {
                        <div class="photo-card">
                            <img src="@photo.DataUrl" alt="@photo.Caption" class="photo-thumb" @onclick="() => _previewPhoto = photo" />
                            <div class="photo-caption-row">
                                <input class="form-input photo-caption-input" placeholder="Add caption..."
                                       @bind="photo.Caption" @bind:after="SaveAsync" />
                                <button class="btn btn-danger btn-sm" @onclick="() => RemovePhoto(photo)">🗑</button>
                            </div>
                            <p class="text-small text-muted">@photo.TakenAt.ToLocalTime().ToString("MMM d, h:mm tt")</p>
                        </div>
                    }
                </div>
            }
        </div>

        @if (_previewPhoto is not null)
        {
            <div class="photo-preview-overlay" @onclick="() => _previewPhoto = null">
                <img src="@_previewPhoto.DataUrl" alt="@_previewPhoto.Caption" class="photo-preview-img" />
                @if (!string.IsNullOrEmpty(_previewPhoto.Caption))
                {
                    <p class="photo-preview-caption">@_previewPhoto.Caption</p>
                }
            </div>
        }
    }
    else if (_activeTab == "notes")
    {
        <div class="notes-section">
            <textarea class="form-input notes-textarea" placeholder="General inspection notes..."
                      @bind="_inspection.Notes" @bind:after="SaveAsync" rows="10"></textarea>
        </div>
    }

    <div class="bottom-actions">
        @if (_inspection.Status == InspectionStatus.InProgress)
        {
            <button class="btn btn-success btn-lg" @onclick="CompleteInspection">
                ✅ Complete Inspection
            </button>
        }
        else
        {
            <div class="completed-banner">
                ✅ Completed on @_inspection.CompletedAt?.ToLocalTime().ToString("MMM d, yyyy h:mm tt")
            </div>
        }
    </div>
}

@code {
    [Parameter] public string InspectionId { get; set; } = "";
    private Inspection? _inspection;
    private string _activeTab = "checklist";
    private string? _expandedItemId;
    private InspectionPhoto? _previewPhoto;

    protected override async Task OnInitializedAsync()
    {
        _inspection = await Store.GetInspectionAsync(InspectionId);
    }

    private async Task SetResult(ChecklistItem item, CheckResult result)
    {
        item.Result = item.Result == result ? CheckResult.NotChecked : result;
        await SaveAsync();
    }

    private void ToggleItemNotes(string itemId)
    {
        _expandedItemId = _expandedItemId == itemId ? null : itemId;
    }

    private string GetItemClass(ChecklistItem item) => item.Result switch
    {
        CheckResult.Pass => "item-pass",
        CheckResult.Fail => "item-fail",
        CheckResult.NotApplicable => "item-na",
        _ => ""
    };

    private async Task OnPhotoSelected(InputFileChangeEventArgs e)
    {
        if (_inspection is null) return;

        foreach (var file in e.GetMultipleFiles(5))
        {
            try
            {
                // Read file as base64 (limit to 10MB)
                var buffer = new byte[file.Size];
                await file.OpenReadStream(maxAllowedSize: 10 * 1024 * 1024).ReadAsync(buffer);
                var dataUrl = $"data:{file.ContentType};base64,{Convert.ToBase64String(buffer)}";

                // Resize to save storage
                var resized = await JS.InvokeAsync<string>("photoHelper.resizeImage", dataUrl, 1280, 960, 0.75);

                var photo = new InspectionPhoto
                {
                    FileName = file.Name,
                    DataUrl = resized,
                    TakenAt = DateTime.UtcNow
                };
                _inspection.Photos.Add(photo);
            }
            catch
            {
                // Skip photos that fail to load
            }
        }
        await SaveAsync();
    }

    private async Task RemovePhoto(InspectionPhoto photo)
    {
        _inspection?.Photos.Remove(photo);
        await SaveAsync();
    }

    private async Task CompleteInspection()
    {
        if (_inspection is null) return;
        _inspection.Status = InspectionStatus.Completed;
        _inspection.CompletedAt = DateTime.UtcNow;
        await SaveAsync();
    }

    private async Task SaveAsync()
    {
        if (_inspection is null) return;
        _inspection.SyncStatus = SyncStatus.Pending;
        await Store.SaveInspectionAsync(_inspection);
    }

    private void GoBack()
    {
        if (_inspection is not null)
            Nav.NavigateTo($"/site/{_inspection.SiteId}");
        else
            Nav.NavigateTo("/");
    }
}

