.top-bar-right {
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 0.75rem;
}

.connectivity-badge {
    padding: 3px 8px;
    border-radius: 20px;
    font-weight: 600;
    text-transform: uppercase;
    font-size: 0.65rem;
    letter-spacing: 0.5px;
