/* ============================================
   Site Inspector — Mobile-first CSS
   ============================================ */

:root {
    --primary: #e94560;
    --primary-dark: #c73450;
    --success: #27ae60;
    --danger: #e74c3c;
    --warning: #f39c12;
    --muted: #95a5a6;
    --bg: #f5f6fa;
    --surface: #ffffff;
    --text: #2c3e50;
    --text-secondary: #7f8c8d;
    --border: #e0e0e0;
