*, *::before, *::after {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
}

html, body {
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    background: var(--bg);
    color: var(--text);
    font-size: 16px;
    line-height: 1.5;
    -webkit-font-smoothing: antialiased;
    -webkit-tap-highlight-color: transparent;
    overscroll-behavior: none;
}

/* ---- Top bar ---- */
.app-container {
    min-height: 100dvh;
    display: flex;
    flex-direction: column;
}

.top-bar {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 10px 16px;
    background: var(--text);
    color: #fff;
    position: sticky;
    top: 0;
    z-index: 100;
    gap: 8px;
}

.app-title {
    color: #fff;
    text-decoration: none;
    font-weight: 700;
    font-size: 1.1rem;
    white-space: nowrap;
}

.top-bar-right {
    display: flex;
    align-items: center;
    gap: 8px;
    font-size: 0.75rem;
}

.connectivity-badge {
    padding: 3px 8px;
    border-radius: 20px;
    font-weight: 600;
    text-transform: uppercase;
    font-size: 0.65rem;
    letter-spacing: 0.5px;
}

.connectivity-badge.online {
    background: var(--success);
    color: #fff;
}

.connectivity-badge.offline {
    background: var(--warning);
    color: #000;
}

.sync-status {
    color: rgba(255,255,255,0.7);
    font-size: 0.75rem;
}

